import'dart:convert';import'package:flutter/material.dart';import'package:flutter/services.dart';import'package:flutter_riverpod/flutter_riverpod.dart';import'package:oraculo_ia/src/design_system/components/oraculo_scaffold.dart';import'package:oraculo_ia/src/features/progress/data/local_learning_state.dart';
class CareerPath{const CareerPath(this.id,this.priority,this.title,this.level,this.skills,this.missions,this.projects,this.hours,this.finalEvaluation);final String id,title,level,finalEvaluation;final int priority,hours;final List<String>skills,missions,projects;}
List<CareerPath>parseCareerPaths(String s){final r=jsonDecode(s)as Map<String,dynamic>;return(r['paths']as List).cast<Map<String,dynamic>>().map((p){List<String>l(String k)=>(p[k]as List).cast<String>();return CareerPath(p['id']as String,p['priority']as int,p['title']as String,p['level']as String,l('skills'),l('missions'),l('projects'),p['hours']as int,p['final']as String);}).toList()..sort((a,b)=>a.priority.compareTo(b.priority));}
class CareerPathsScreen extends ConsumerWidget{const CareerPathsScreen({super.key});@override Widget build(BuildContext c,WidgetRef ref){final completed=ref.watch(learningStateProvider).value?.completed.length??0;return OraculoScaffold(body:FutureBuilder<List<CareerPath>>(future:rootBundle.loadString('knowledge/career_paths_v1.json').then(parseCareerPaths),builder:(c,s){if(!s.hasData)return const Center(child:CircularProgressIndicator());return ListView(children:[Text('Caminos profesionales',style:Theme.of(c).textTheme.headlineMedium),const Text('Prioridad personalizada para Carlos.'),for(final p in s.data!)Card(child:ExpansionTile(title:Text('${p.priority}. ${p.title}'),subtitle:Text('${p.level} · ${p.hours} h'),childrenPadding:const EdgeInsets.all(16),children:[LinearProgressIndicator(value:(completed/p.missions.length).clamp(0,1)),ListTile(title:const Text('Habilidades'),subtitle:Text(p.skills.join(' · '))),ListTile(title:const Text('Misiones obligatorias'),subtitle:Text(p.missions.join(' · '))),ListTile(title:const Text('Proyectos'),subtitle:Text(p.projects.join(' · '))),ListTile(title:const Text('Conocimientos pendientes'),subtitle:Text('${(p.missions.length-completed).clamp(0,p.missions.length)} misiones del camino')),ListTile(title:const Text('Evaluación final'),subtitle:Text(p.finalEvaluation))]))]);}));}}
